function searchFilter(e,t){for(var r=document.getElementById(e),l=document.getElementById(t),n=new RegExp(r.value,"i"),c=!1,s=1;s<l.rows.length;s++){c=!1;for(var o=l.rows[s].cells.length-1;o>=0&&!(c=n.test(l.rows[s].cells[o].innerHTML));o--);l.rows[s].style.display=c?"":"none"}}document.querySelectorAll(".close-filter").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault(),document.querySelector(".search__filter-properties").classList.toggle("active")})}),document.querySelector("#searchClient").addEventListener("keyup",()=>{searchFilter("searchClient","tableClient")});